		rcfg, rt := makeRuntime("worker-a")
		_, _ = workerA.Run(context.Background(), rcfg, rt)
	}()
	go func() {
		defer wg.Done()
		rcfg, rt := makeRuntime("worker-b")
		_, _ = workerB.Run(context.Background(), rcfg, rt)
	}()

	select {
	case <-lintStarted:
