func (r ExecuteBeadLoopRuntime) loopIntent() (executeloop.Mode, time.Duration) {
	mode := r.Mode
	if mode == "" {
		if r.Once {
			mode = executeloop.ModeOnce
		} else {
			mode = executeloop.ModeDrain
		}
	}
	idleInterval := r.IdleInterval
	if idleInterval == 0 && mode == executeloop.ModeWatch {
		idleInterval = r.PollInterval
	}
	if idleInterval == 0 && mode == executeloop.ModeWatch {
		idleInterval = 30 * time.Second
	}
	return mode, idleInterval
}

// Package failclass implements the FEAT-004 failure-classification routing
// policy applied by ddx work between bead-execution attempts (bead
// ddx-d27a1895).
//
// It provides four things the queue drain composes:
//
//   - Classify maps a single attempt Outcome to exactly one routing Action,
//     applying the normative failure-classification table.
//   - Escalate owns the single one-hop middle->max tier escalation, which only
//     a typed genuine failure triggers.
//   - Pool enforces a per-pool in-flight max-attempt cap that prevents a
//     multi-worker stampede when many workers fail concurrently.
//   - Pool also carries the global (per-pool, not per-bead) cooldown applied on
//     quota exhaustion.
//
// The classification table is normative; it is inlined here from the bead body
// because the upstream FEAT-004 routing addendum lives in the fizeau repo and
// is not reachable from a cold ddx agent.
package failclass

import (
	"sync"
	"time"
)

// Outcome is the typed result of a single ddx-work attempt. Every Outcome maps
// to exactly one Action via Classify.
type Outcome string

const (
	// OutcomeSuccess: the attempt satisfied the bead's acceptance criteria.
	OutcomeSuccess Outcome = "success"
	// OutcomeAlreadySatisfied: the bead was already satisfied before work.
	OutcomeAlreadySatisfied Outcome = "already_satisfied"
	// OutcomeNoChanges: the agent produced nothing and wrote a rationale.
	OutcomeNoChanges Outcome = "no_changes"
	// OutcomeGenuineFailure: tests fail after real work; acceptance unmet.
	// This is the only outcome that can trigger a tier escalation.
	OutcomeGenuineFailure Outcome = "genuine_failure"
	// OutcomeDirtyWorktree: dirty worktree or partial write.
	OutcomeDirtyWorktree Outcome = "dirty_worktree"
	// OutcomeTransport: provider transport failure (i/o timeout, conn refused,
	// 5xx).
	OutcomeTransport Outcome = "transport"
	// OutcomeQuota: quota exhausted (retry_after).
	OutcomeQuota Outcome = "quota"
	// OutcomeAuth: auth/config missing.
	OutcomeAuth Outcome = "auth"
	// OutcomeSetup: toolchain/setup failure.
	OutcomeSetup Outcome = "setup"
	// OutcomeTimeout: timeout / no-progress watchdog.
	OutcomeTimeout Outcome = "timeout"
	// OutcomeMergeConflict: merge/land conflict.
	OutcomeMergeConflict Outcome = "merge_conflict"
)

// Action is the single routing action selected for an Outcome.
type Action string

const (
	// ActionCloseBead: close the bead (success path).
	ActionCloseBead Action = "close_bead"
	// ActionCloseOrUnclaim: close or unclaim per the agent's rationale; never
	// escalate the tier.
	ActionCloseOrUnclaim Action = "close_or_unclaim"
	// ActionEscalateTier: escalate the tier exactly once (middle->max).
	ActionEscalateTier Action = "escalate_tier"
	// ActionResetRetrySameTier: clean/reset the worktree and retry at the same
	// tier (not an escalation).
	ActionResetRetrySameTier Action = "reset_retry_same_tier"
	// ActionRerouteSameTier: reroute to another dispatchable candidate at the
	// same tier; no tier change.
	ActionRerouteSameTier Action = "reroute_same_tier"
	// ActionGlobalCooldown: put the whole pool to sleep until quota reset; not
	// a per-bead mutation, not an escalation.
	ActionGlobalCooldown Action = "global_cooldown"
	// ActionOperatorAttention: explicit bead state transition to the operator
	// lane (not a notification or an indefinite wait).
	ActionOperatorAttention Action = "operator_attention"
	// ActionUnclaimRetryLater: unclaim and retry later; not an escalation.
	ActionUnclaimRetryLater Action = "unclaim_retry_later"
)

// Escalates reports whether the Action mutates the tier. Only
// ActionEscalateTier escalates; this is the single guard the escalation owner
// (ddx work) checks before calling Escalate.
func (a Action) Escalates() bool {
	return a == ActionEscalateTier
}

// ClassifyContext carries the routing state needed to resolve the tier- and
// attempt-conditional rows of the table (genuine failure and timeout).
type ClassifyContext struct {
	// AtMaxTier reports whether the attempt already ran at the maximum tier. A
	// genuine failure at the max tier goes to the operator lane instead of
	// escalating.
	AtMaxTier bool
	// SameTierRetried reports whether a same-tier retry was already consumed. A
	// second timeout (after one same-tier retry) goes to the operator lane.
	SameTierRetried bool
}

// Classify maps a single attempt Outcome to exactly one Action, applying the
// normative failure-classification table.
//
// Only OutcomeGenuineFailure can produce ActionEscalateTier, and only when the
// attempt was not already at the max tier. The no_changes, dirty, transport,
// quota, auth, setup, timeout, and merge-conflict outcomes never escalate.
func Classify(outcome Outcome, ctx ClassifyContext) Action {
	switch outcome {
	case OutcomeSuccess, OutcomeAlreadySatisfied:
		return ActionCloseBead
	case OutcomeNoChanges:
		return ActionCloseOrUnclaim
	case OutcomeGenuineFailure:
		// Single one-hop middle->max escalation; a max-tier genuine failure
		// stops escalating and goes to the operator lane.
		if ctx.AtMaxTier {
			return ActionOperatorAttention
		}
		return ActionEscalateTier
	case OutcomeDirtyWorktree:
		return ActionResetRetrySameTier
	case OutcomeTransport:
		return ActionRerouteSameTier
	case OutcomeQuota:
		return ActionGlobalCooldown
	case OutcomeAuth, OutcomeSetup:
		return ActionOperatorAttention
	case OutcomeTimeout:
		// Clean + same-tier retry once, then operator-attention.
		if ctx.SameTierRetried {
			return ActionOperatorAttention
		}
		return ActionResetRetrySameTier
	case OutcomeMergeConflict:
		return ActionUnclaimRetryLater
	default:
		// Unknown outcomes go to the operator lane rather than silently
		// escalating or retrying.
		return ActionOperatorAttention
	}
}

// Tier is a routing capability tier. Escalation is a single one-hop edge from
// TierMiddle to TierMax; no other edge escalates.
type Tier int

const (
	// TierLow is the cheapest tier and is never an escalation target.
	TierLow Tier = iota
	// TierMiddle is the default starting tier for dispatch.
	TierMiddle
	// TierMax is the strongest tier and the only escalation target.
	TierMax
)

// Escalate performs the single one-hop middle->max escalation and reports
// whether it changed the tier. Escalation is idempotent: only TierMiddle
// escalates (to TierMax); every other tier — including a tier already at
// TierMax — is returned unchanged with escalated=false. This enforces "exactly
// one middle->max" per dispatch chain.
func Escalate(t Tier) (next Tier, escalated bool) {
	if t == TierMiddle {
		return TierMax, true
	}
	return t, false
}

// Pool tracks per-pool in-flight attempts and the global cooldown for a single
// dispatch pool. It is safe for concurrent use by multiple workers.
//
// The in-flight cap prevents a multi-worker stampede: when many workers fail
// concurrently against the same pool, at most maxInFlight attempts may hold a
// slot at once. The cooldown is global to the pool (applied on quota
// exhaustion), not a per-bead mutation.
type Pool struct {
	mu            sync.Mutex
	name          string
	maxInFlight   int
	inFlight      int
	cooldownUntil time.Time
	now           func() time.Time
}

// NewPool returns a Pool with the given name and in-flight cap. A non-positive
// maxInFlight is clamped to 1. The clock defaults to time.Now and can be
// overridden for tests via SetClock.
func NewPool(name string, maxInFlight int) *Pool {
	if maxInFlight < 1 {
		maxInFlight = 1
	}
	return &Pool{
		name:        name,
		maxInFlight: maxInFlight,
		now:         time.Now,
	}
}

// SetClock overrides the pool's time source. It exists so tests can advance
// time without sleeping; the bead requires bounded, non-hanging tests.
func (p *Pool) SetClock(now func() time.Time) {
	p.mu.Lock()
	defer p.mu.Unlock()
	p.now = now
}

// Name returns the pool's name.
func (p *Pool) Name() string {
	return p.name
}

// Acquire attempts to take one in-flight slot. It returns false when the pool
// is in cooldown or the in-flight cap is already reached; otherwise it takes a
// slot and returns true. Every successful Acquire must be paired with a
// Release.
func (p *Pool) Acquire() bool {
	p.mu.Lock()
	defer p.mu.Unlock()
	if p.now().Before(p.cooldownUntil) {
		return false
	}
	if p.inFlight >= p.maxInFlight {
		return false
	}
	p.inFlight++
	return true
}

// Release returns one in-flight slot. It never drops below zero.
func (p *Pool) Release() {
	p.mu.Lock()
	defer p.mu.Unlock()
	if p.inFlight > 0 {
		p.inFlight--
	}
}

// InFlight returns the current number of held in-flight slots.
func (p *Pool) InFlight() int {
	p.mu.Lock()
	defer p.mu.Unlock()
	return p.inFlight
}

// EnterCooldown applies a global pool cooldown of duration d (typically the
// quota retry_after). It is global to the pool, not a per-bead mutation:
// subsequent Acquire calls fail until the cooldown elapses. A later, longer
// cooldown extends the window; a shorter one never shortens an active window.
func (p *Pool) EnterCooldown(d time.Duration) {
	p.mu.Lock()
	defer p.mu.Unlock()
	until := p.now().Add(d)
	if until.After(p.cooldownUntil) {
		p.cooldownUntil = until
	}
}

// InCooldown reports whether the pool is currently in a global cooldown.
func (p *Pool) InCooldown() bool {
	p.mu.Lock()
	defer p.mu.Unlock()
	return p.now().Before(p.cooldownUntil)
}

package agent

import (
	"bytes"
	"context"
	"encoding/json"
	"fmt"
	"strings"
	"sync"
	"sync/atomic"
	"testing"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/agent/executeloop"
	"github.com/DocumentDrivenDX/ddx/internal/bead"
	"github.com/DocumentDrivenDX/ddx/internal/config"
	"github.com/stretchr/testify/assert"
	"github.com/stretchr/testify/require"
)

// TestExecuteBeadWorkerConcurrentPreClaimIntakeRunsOncePerBead is AC #1:
// With two concurrent workers on one ready bead, only the worker that wins
// Store.Claim invokes the model-backed PreClaimIntakeHook. The loser loses at
// Claim (picker.claim_race), never reaches intake, and moves on.
func TestExecuteBeadWorkerConcurrentPreClaimIntakeRunsOncePerBead(t *testing.T) {
	store := bead.NewStore(t.TempDir())
	require.NoError(t, store.Init(context.Background()))
	only := &bead.Bead{ID: "ddx-concurrent-intake", Title: "concurrent intake", Priority: 0}
	require.NoError(t, store.Create(context.Background(), only))

	var intakeCalls atomic.Int32

	// Intake hook blocks so that Worker B has time to lose the Claim race
	// before Worker A's intake returns.
	intakeStarted := make(chan struct{}, 1)
	intakeRelease := make(chan struct{})

	makeRuntime := func(assignee string) (config.ResolvedConfig, ExecuteBeadLoopRuntime) {
		opts := config.TestLoopConfigOpts{
			Assignee:                           assignee,
			BeadQualityLintBlockThresholdScore: 1,
		}
		rcfg := config.NewTestConfigForLoop(opts).Resolve(config.TestLoopOverrides(opts))
		rt := ExecuteBeadLoopRuntime{
			Once: true,
			PreClaimIntakeHook: func(ctx context.Context, beadID string) (PreClaimIntakeResult, error) {
				intakeCalls.Add(1)
				select {
				case intakeStarted <- struct{}{}:
				default:
				}
				select {
				case <-intakeRelease:
				case <-ctx.Done():
				}
				return PreClaimIntakeResult{Outcome: PreClaimIntakeActionableAtomic}, nil
			},
		}
		return rcfg, rt
	}

	executor := ExecuteBeadExecutorFunc(func(ctx context.Context, beadID string) (ExecuteBeadReport, error) {
		return ExecuteBeadReport{BeadID: beadID, Status: ExecuteBeadStatusSuccess, ResultRev: "rev"}, nil
	})
	workerA := &ExecuteBeadWorker{Store: store, Executor: executor}
	workerB := &ExecuteBeadWorker{Store: store, Executor: executor}

	var wg sync.WaitGroup
	wg.Add(2)
	go func() {
		defer wg.Done()
		rcfg, rt := makeRuntime("worker-a")
		_, _ = workerA.Run(context.Background(), rcfg, rt)
	}()
	go func() {
		defer wg.Done()
		rcfg, rt := makeRuntime("worker-b")
		_, _ = workerB.Run(context.Background(), rcfg, rt)
	}()

	// Wait for exactly one intake invocation to start, then release it.
	// If neither starts within 5s the test hangs on wg.Wait and fails via
	// t.Cleanup timeout rather than silently passing.
	select {
	case <-intakeStarted:
	case <-time.After(5 * time.Second):
		t.Fatal("intake hook never started — no worker claimed the bead")
	}
	close(intakeRelease)
	wg.Wait()

	assert.Equal(t, int32(1), intakeCalls.Load(),
		"only the claiming worker must enter intake; the Claim-loser must not run the model-backed hook")
}

// TestExecuteBeadWorkerConcurrentPreDispatchLintDoesNotDuplicateEvents is AC #2:
// Two concurrent workers on the same bead must not append duplicate
// bead-quality.lint events. With claim-first ordering, only the owning worker
// appends the lint event; the loser never reaches the lint gate.
func TestExecuteBeadWorkerConcurrentPreDispatchLintDoesNotDuplicateEvents(t *testing.T) {
	inner := bead.NewStore(t.TempDir())
	require.NoError(t, inner.Init(context.Background()))
	only := &bead.Bead{ID: "ddx-concurrent-lint", Title: "concurrent lint", Priority: 0}
	require.NoError(t, inner.Create(context.Background(

	// Lint hook blocks to widen the concurrency window.
	), only))

	lintStarted := make(chan struct{}, 1)
	lintRelease := make(chan struct{})

	makeRuntime := func(assignee string) (config.ResolvedConfig, ExecuteBeadLoopRuntime) {
		opts := config.TestLoopConfigOpts{
			Assignee:                           assignee,
			BeadQualityLintBlockThresholdScore: 1,
		}
		rcfg := config.NewTestConfigForLoop(opts).Resolve(config.TestLoopOverrides(opts))
		rt := ExecuteBeadLoopRuntime{
			Once: true,
			PreDispatchLintHook: func(ctx context.Context, beadID string) (LintResult, error) {
				select {
				case lintStarted <- struct{}{}:
				default:
				}
				select {
				case <-lintRelease:
				case <-ctx.Done():
				}
				return LintResult{Score: 9, Rationale: "ready"}, nil
			},
		}
		return rcfg, rt
	}

	executor := ExecuteBeadExecutorFunc(func(ctx context.Context, beadID string) (ExecuteBeadReport, error) {
		return ExecuteBeadReport{BeadID: beadID, Status: ExecuteBeadStatusSuccess, ResultRev: "rev"}, nil
	})
	workerA := &ExecuteBeadWorker{Store: inner, Executor: executor}
	workerB := &ExecuteBeadWorker{Store: inner, Executor: executor}

	var wg sync.WaitGroup
	wg.Add(2)
	go func() {
		defer wg.Done()
		rcfg, rt := makeRuntime("worker-a")
		_, _ = workerA.Run(context.Background(), rcfg, rt)
	}()
	go func() {
		defer wg.Done()
		rcfg, rt := makeRuntime("worker-b")
		_, _ = workerB.Run(context.Background(), rcfg, rt)
	}()

	select {
	case <-lintStarted:
	case <-time.After(5 * time.Second):
		t.Fatal("lint hook never started")
	}
	close(lintRelease)
	wg.Wait()

	events, err := inner.Events(only.ID)
	require.NoError(t, err)
	var lintEvents []bead.BeadEvent
	for _, ev := range events {
		if ev.Kind == "bead-quality.lint" {
			lintEvents = append(lintEvents, ev)
		}
	}
	assert.Equal(t, 1, len(lintEvents),
		"exactly one bead-quality.lint event must be appended; concurrent workers must not duplicate it")
}

// TestPreClaimIntakeRewriteRequiresOwnedReservation is AC #3:
// With actionable_but_rewritten intake, only the claiming worker applies
// description/acceptance rewrites. Concurrent losers cannot double-rewrite
// or append conflicting events because they never reach applyPreClaimIntakeRewrite.
func TestPreClaimIntakeRewriteRequiresOwnedReservation(t *testing.T) {
	inner := bead.NewStore(t.TempDir())
	require.NoError(t, inner.Init(context.Background()))

	original := &bead.Bead{
		ID:          "ddx-rewrite-concurrent",
		Title:       "rewrite ownership",
		Priority:    0,
		Description: "PROBLEM\noriginal problem\n\nROOT CAUSE\noriginal cause\n\nPROPOSED FIX\noriginal fix\n",
		Acceptance:  "1. original criterion\n2. name the test",
	}
	require.NoError(t, inner.Create(context.Background(), original))

	var rewriteCalls atomic.Int32
	rewriteStarted := make(chan struct{}, 1)
	rewriteRelease := make(chan struct{})

	makeRuntime := func(assignee string) (config.ResolvedConfig, ExecuteBeadLoopRuntime) {
		opts := config.TestLoopConfigOpts{Assignee: assignee}
		rcfg := config.NewTestConfigForLoop(opts).Resolve(config.TestLoopOverrides(opts))
		rt := ExecuteBeadLoopRuntime{
			Once: true,
			PreClaimIntakeHook: func(ctx context.Context, beadID string) (PreClaimIntakeResult, error) {
				rewriteCalls.Add(1)
				select {
				case rewriteStarted <- struct{}{}:
				default:
				}
				select {
				case <-rewriteRelease:
				case <-ctx.Done():
				}
				return PreClaimIntakeResult{
					Outcome: PreClaimIntakeActionableButRewritten,
					Detail:  "safe refinement",
					Rewrite: PreClaimIntakeRewrite{
						Description:   "PROBLEM\noriginal problem\n\nROOT CAUSE\noriginal cause\n\nPROPOSED FIX\noriginal fix\n\nAdd explicit validation step.",
						Acceptance:    "1. original criterion\n2. name the test\n3. lefthook run pre-commit passes",
						ChangedFields: []string{"description", "acceptance"},
					},
				}, nil
			},
		}
		return rcfg, rt
	}

	executor := ExecuteBeadExecutorFunc(func(ctx context.Context, beadID string) (ExecuteBeadReport, error) {
		return ExecuteBeadReport{BeadID: beadID, Status: ExecuteBeadStatusSuccess, ResultRev: "rev"}, nil
	})
	workerA := &ExecuteBeadWorker{Store: inner, Executor: executor}
	workerB := &ExecuteBeadWorker{Store: inner, Executor: executor}

	var wg sync.WaitGroup
	wg.Add(2)
	go func() {
		defer wg.Done()
		rcfg, rt := makeRuntime("worker-a")
		_, _ = workerA.Run(context.Background(), rcfg, rt)
	}()
	go func() {
		defer wg.Done()
		rcfg, rt := makeRuntime("worker-b")
		_, _ = workerB.Run(context.Background(), rcfg, rt)
	}()

	select {
	case <-rewriteStarted:
	case <-time.After(5 * time.Second):
		t.Fatal("intake hook never started")
	}
	close(rewriteRelease)
	wg.Wait()

	// Only the claiming worker runs intake and reaches the rewrite path.
	assert.Equal(t, int32(1), rewriteCalls.Load(),
		"only the claiming worker must run the rewrite intake hook; concurrent losers must not reach it")

	// The description must be rewritten exactly once: contains the added
	// text but does not contain it twice (no double-rewrite).
	got, err := inner.Get(context.Background(), original.ID)
	require.NoError(t, err)
	count := strings.Count(got.Description, "Add explicit validation step.")
	assert.Equal(t, 1, count,
		"description must be rewritten exactly once; double-rewrite would indicate a concurrent write")

	// Exactly one intake-rewritten event must exist.
	events, err := inner.Events(original.ID)
	require.NoError(t, err)
	var rewriteEvents int
	for _, ev := range events {
		if ev.Kind == "intake-rewritten" {
			rewriteEvents++
		}
	}
	assert.Equal(t, 1, rewriteEvents,
		"exactly one intake-rewritten event must be recorded; duplicates indicate concurrent rewrite")
}

// TestExecuteBeadWorkerReadinessRejectReleasesOrParksClaim is AC #4:
// Covers the post-claim outcomes when intake or lint rejects the bead:
//   - infra error: fail-open, proceed to execution
//   - operator_required during queue drain: warn and proceed to execution
//   - operator_required during targeted execution: move bead to status=proposed and unclaim
//   - lint-blocked: unclaim bead, no execution
//   - actionable_atomic: proceed to implementation normally
func TestExecuteBeadWorkerReadinessRejectReleasesOrParksClaim(t *testing.T) {
	t.Run("intake_infra_error_proceeds_to_execution", func(t *testing.T) {
		store, candidate, _ := newExecuteLoopTestStore(t)
		var execCalled atomic.Int32
		worker := &ExecuteBeadWorker{
			Store: store,
			Executor: ExecuteBeadExecutorFunc(func(ctx context.Context, beadID string) (ExecuteBeadReport, error) {
				execCalled.Add(1)
				return ExecuteBeadReport{BeadID: beadID, Status: ExecuteBeadStatusSuccess, ResultRev: "rev"}, nil
			}),
		}
		opts := config.TestLoopConfigOpts{
			Assignee:                           "worker",
			BeadQualityLintBlockThresholdScore: 5,
		}
		rcfg := config.NewTestConfigForLoop(opts).Resolve(config.TestLoopOverrides(opts))

		result, err := worker.Run(context.Background(), rcfg, ExecuteBeadLoopRuntime{
			Once: true,
			PreClaimIntakeHook: func(ctx context.Context, beadID string) (PreClaimIntakeResult, error) {
				return PreClaimIntakeResult{}, fmt.Errorf("intake service timeout")
			},
		})
		require.NoError(t, err)
		require.NotNil(t, result)

		assert.Equal(t, int32(1), execCalled.Load(), "infra error must fail open and proceed to execution")
		assert.Equal(t, 1, result.Successes)

		got, err := store.Get(context.Background(), candidate.ID)
		require.NoError(t, err)
		assert.Equal(t, bead.StatusClosed, got.Status, "bead must be closed after successful execution")
	})

	t.Run("operator_required_warns_and_executes_during_queue_drain", func(t *testing.T) {
		store, candidate, _ := newExecuteLoopTestStore(t)
		var eventSink bytes.Buffer
		var execCalled atomic.Int32
		worker := &ExecuteBeadWorker{
			Store: store,
			Executor: ExecuteBeadExecutorFunc(func(ctx context.Context, beadID string) (ExecuteBeadReport, error) {
				execCalled.Add(1)
				return ExecuteBeadReport{BeadID: beadID, Status: ExecuteBeadStatusSuccess, ResultRev: "rev"}, nil
			}),
		}
		opts := config.TestLoopConfigOpts{
			Assignee:                           "worker",
			BeadQualityLintBlockThresholdScore: 5,
		}
		rcfg := config.NewTestConfigForLoop(opts).Resolve(config.TestLoopOverrides(opts))

		result, err := worker.Run(context.Background(), rcfg, ExecuteBeadLoopRuntime{
			Once:      true,
			EventSink: &eventSink,
			PreClaimIntakeHook: func(ctx context.Context, beadID string) (PreClaimIntakeResult, error) {
				return PreClaimIntakeResult{
					Outcome: PreClaimIntakeOperatorRequired,
					Detail:  "missing root cause with file:line",
				}, nil
			},
		})
		require.NoError(t, err)
		require.NotNil(t, result)

		assert.Equal(t, int32(1), execCalled.Load(), "broad queue drain should attempt work despite intake uncertainty")
		assert.Equal(t, 1, result.Attempts)
		assert.Equal(t, 1, result.Successes)

		got, err := store.Get(context.Background(), candidate.ID)
		require.NoError(t, err)
		assert.Equal(t, bead.StatusClosed, got.Status, "successful best-effort attempt should close normally")
		assert.NotContains(t, got.Labels, bead.LabelNeedsHuman,
			"best-effort intake warning must not rely on needs_human label parking")
		assert.Empty(t, bead.GetNeedsHumanMeta(*got).Reason)

		// An intake.warn event is still recorded as evidence for review/follow-up,
		// but it does not park the bead in broad queue-drain mode.
		events, err := store.Events(candidate.ID)
		require.NoError(t, err)
		var foundWarn bool
		for _, ev := range events {
			if ev.Kind != "intake.warn" {
				continue
			}
			foundWarn = true
			var body map[string]any
			require.NoError(t, json.Unmarshal([]byte(ev.Body), &body))
			assert.Equal(t, "readiness_best_effort", body["reason"])
		}
		assert.True(t, foundWarn, "an intake.warn event must be recorded as review evidence")

		// The event stream must contain pre_claim_intake.blocked.
		assert.Contains(t, eventSink.String(), "pre_claim_intake.blocked")
	})

	t.Run("operator_required_targeted_proposes_and_unclaims", func(t *testing.T) {
		store, candidate, _ := newExecuteLoopTestStore(t)
		var eventSink bytes.Buffer
		worker := &ExecuteBeadWorker{
			Store: store,
			Executor: ExecuteBeadExecutorFunc(func(ctx context.Context, beadID string) (ExecuteBeadReport, error) {
				t.Fatal("executor must not run for terminal intake outcomes in targeted mode")
				return ExecuteBeadReport{}, nil
			}),
		}
		opts := config.TestLoopConfigOpts{
			Assignee:                           "worker",
			BeadQualityLintBlockThresholdScore: 5,
		}
		rcfg := config.NewTestConfigForLoop(opts).Resolve(config.TestLoopOverrides(opts))

		result, err := worker.Run(context.Background(), rcfg, ExecuteBeadLoopRuntime{
			Once:         true,
			TargetBeadID: candidate.ID,
			EventSink:    &eventSink,
			PreClaimIntakeHook: func(ctx context.Context, beadID string) (PreClaimIntakeResult, error) {
				return PreClaimIntakeResult{
					Outcome: PreClaimIntakeOperatorRequired,
					Detail:  "missing root cause with file:line",
				}, nil
			},
		})
		require.NoError(t, err)
		require.NotNil(t, result)

		assert.Equal(t, 0, result.Attempts, "targeted terminal intake outcome must not count as an attempt")

		got, err := store.Get(context.Background(), candidate.ID)
		require.NoError(t, err)
		assert.Equal(t, bead.StatusProposed, got.Status, "targeted execution may park for operator attention")
		assert.Empty(t, got.Owner, "bead must be unclaimed after targeted terminal intake")
		assert.NotContains(t, got.Labels, bead.LabelNeedsHuman,
			"terminal intake outcome must not rely on needs_human label parking")
		assert.Equal(t, "operator_required", bead.GetNeedsHumanMeta(*got).Reason)

		events, err := store.Events(candidate.ID)
		require.NoError(t, err)
		var foundBlocked bool
		for _, ev := range events {
			if ev.Kind != "intake.blocked" {
				continue
			}
			foundBlocked = true
			var body map[string]any
			require.NoError(t, json.Unmarshal([]byte(ev.Body), &body))
			assert.Equal(t, string(PreClaimIntakeOperatorRequired), body["intake_outcome"])
		}
		assert.True(t, foundBlocked, "an intake.blocked event must be recorded when targeted execution parks")
		assert.Contains(t, eventSink.String(), "pre_claim_intake.blocked")
	})

	t.Run("timeout_warns_and_executes_original_bead_in_watch_mode", func(t *testing.T) {
		store, first, _ := newExecuteLoopTestStore(t)
